package com.automation.pages;

import com.automation.base.BasePage;
import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;

/**
 * LoginPage — Login feature page actions and locators
 * Generated by: ScriptGenerationAgent | Framework: Selenium Java
 */
public class LoginPage extends BasePage {

    // ── Locators ──────────────────────────────────────────────────────────────
    private final By emailInput = By.cssSelector("input[type='email']");
    private final By passwordInput = By.cssSelector("input[type='password']");
    private final By loginButton = By.cssSelector("button[type='submit']");
    private final By errorMessage = By.cssSelector("[role='alert']");
    private final By loginPageHeading = By.cssSelector("h1");
    private final By registerLink = By.linkText("Register");

    public LoginPage(WebDriver driver) {
        super(driver);
    }

    // ── Navigation ────────────────────────────────────────────────────────────

    public void navigateToLoginPage() {
        String baseUrl = System.getenv("BASE_URL");
        if (baseUrl == null || baseUrl.isEmpty()) {
            baseUrl = "http://192.168.10.124:4001";
        }
        driver.get(baseUrl);
        waitForPageLoad();
    }

    // ── Actions ───────────────────────────────────────────────────────────────

    public void enterEmail(String email) {
        waitForElementVisible(emailInput);
        driver.findElement(emailInput).clear();
        driver.findElement(emailInput).sendKeys(email);
    }

    public void enterPassword(String password) {
        waitForElementVisible(passwordInput);
        driver.findElement(passwordInput).clear();
        driver.findElement(passwordInput).sendKeys(password);
    }

    public void clickLoginButton() {
        waitForElementClickable(loginButton);
        driver.findElement(loginButton).click();
        waitForPageLoad();
    }

    public void login(String email, String password) {
        enterEmail(email);
        enterPassword(password);
        clickLoginButton();
    }

    public void clearEmailField() {
        waitForElementVisible(emailInput);
        driver.findElement(emailInput).clear();
    }

    public void clearPasswordField() {
        waitForElementVisible(passwordInput);
        driver.findElement(passwordInput).clear();
    }

    // ── Assertions ────────────────────────────────────────────────────────────

    public boolean isLoginPageDisplayed() {
        waitForPageLoad();
        return isElementVisible(loginPageHeading) 
            && isElementVisible(emailInput) 
            && isElementVisible(passwordInput)
            && isElementVisible(loginButton);
    }

    public boolean isErrorMessageDisplayed() {
        try {
            WebDriverWait wait = new WebDriverWait(driver, Duration.ofSeconds(5));
            wait.until(ExpectedConditions.visibilityOfElementLocated(errorMessage));
            return true;
        } catch (Exception e) {
            return false;
        }
    }

    public String getErrorMessageText() {
        waitForElementVisible(errorMessage);
        return driver.findElement(errorMessage).getText();
    }

    public boolean isRegisterLinkDisplayed() {
        return isElementVisible(registerLink);
    }

    public String getCurrentUrl() {
        return driver.getCurrentUrl();
    }

    public boolean isUrlContaining(String fragment) {
        return getCurrentUrl().contains(fragment);
    }
}